        /// <summary>SnapshotStreamDeallocate (0x000A).</summary>
        public const uint SnapshotStreamDeallocate = 0x000A;
        /// <summary>SetStreamPriorities (0x000B).</summary>
        public const uint SetStreamPriorities = 0x000B;
        /// <summary>CaptureSnapshot (0x000C).</summary>
        public const uint CaptureSnapshot = 0x000C;
    }

    // Async command methods

    /// <summary>Send AudioStreamAllocate command (0x0000).</summary>
    public Task<InvokeResponse> AudioStreamAllocateAsync(
        StreamUsageEnum streamUsage,
        AudioCodecEnum audioCodec,
        byte channelCount,
        uint sampleRate,
        uint bitRate,
        byte bitDepth,
        CancellationToken ct = default)
        => InvokeCommandAsync(0x0000, tlv =>
        {
            tlv.AddUInt8(0, (byte)streamUsage);
            tlv.AddUInt8(1, (byte)audioCodec);
            tlv.AddUInt8(2, channelCount);
            tlv.AddUInt32(3, sampleRate);
            tlv.AddUInt32(4, bitRate);
            tlv.AddUInt8(5, bitDepth);
        }, ct);

    /// <summary>Send AudioStreamDeallocate command (0x0002).</summary>
    public Task<InvokeResponse> AudioStreamDeallocateAsync(
        ushort audioStreamID,
        CancellationToken ct = default)
        => InvokeCommandAsync(0x0002, tlv => { tlv.AddUInt16(0, audioStreamID); }, ct);

    /// <summary>Send VideoStreamAllocate command (0x0003).</summary>
    public Task<InvokeResponse> VideoStreamAllocateAsync(
        StreamUsageEnum streamUsage,
        VideoCodecEnum videoCodec,
        ushort minFrameRate,
        ushort maxFrameRate,
        VideoResolutionStruct minResolution,
        VideoResolutionStruct maxResolution,
        uint minBitRate,
        uint maxBitRate,
        ushort keyFrameInterval,
        bool? watermarkEnabled = default,
        bool? oSDEnabled = default,
        CancellationToken ct = default)
        => InvokeCommandAsync(0x0003, tlv =>
        {
            tlv.AddUInt8(0, (byte)streamUsage);
            tlv.AddUInt8(1, (byte)videoCodec);
            tlv.AddUInt16(2, minFrameRate);
            tlv.AddUInt16(3, maxFrameRate);
            WriteVideoResolutionStruct(tlv, 4, minResolution);
            WriteVideoResolutionStruct(tlv, 5, maxResolution);
            tlv.AddUInt32(6, minBitRate);
            tlv.AddUInt32(7, maxBitRate);
            tlv.AddUInt16(8, keyFrameInterval);
            if (watermarkEnabled != null) tlv.AddBool(9, watermarkEnabled.Value);
            if (oSDEnabled != null) tlv.AddBool(10, oSDEnabled.Value);
        }, ct);

    /// <summary>Send VideoStreamModify command (0x0005).</summary>
    public Task<InvokeResponse> VideoStreamModifyAsync(
        ushort videoStreamID,
        bool? watermarkEnabled = default,
        bool? oSDEnabled = default,
        CancellationToken ct = default)
        => InvokeCommandAsync(0x0005, tlv =>
        {
            tlv.AddUInt16(0, videoStreamID);
            if (watermarkEnabled != null) tlv.AddBool(1, watermarkEnabled.Value);
            if (oSDEnabled != null) tlv.AddBool(2, oSDEnabled.Value);
        }, ct);

    /// <summary>Send VideoStreamDeallocate command (0x0006).</summary>
    public Task<InvokeResponse> VideoStreamDeallocateAsync(
        ushort videoStreamID,
        CancellationToken ct = default)
        => InvokeCommandAsync(0x0006, tlv => { tlv.AddUInt16(0, videoStreamID); }, ct);

    /// <summary>Send SnapshotStreamAllocate command (0x0007).</summary>
    public Task<InvokeResponse> SnapshotStreamAllocateAsync(
        ImageCodecEnum imageCodec,
        ushort maxFrameRate,
        VideoResolutionStruct minResolution,
        VideoResolutionStruct maxResolution,
        byte quality,
        bool? watermarkEnabled = default,
        bool? oSDEnabled = default,
        CancellationToken ct = default)
        => InvokeCommandAsync(0x0007, tlv =>
        {
            tlv.AddUInt8(0, (byte)imageCodec);
            tlv.AddUInt16(1, maxFrameRate);
            WriteVideoResolutionStruct(tlv, 2, minResolution);
            WriteVideoResolutionStruct(tlv, 3, maxResolution);
            tlv.AddUInt8(4, quality);
            if (watermarkEnabled != null) tlv.AddBool(5, watermarkEnabled.Value);
            if (oSDEnabled != null) tlv.AddBool(6, oSDEnabled.Value);
        }, ct);

    /// <summary>Send SnapshotStreamModify command (0x0009).</summary>
    public Task<InvokeResponse> SnapshotStreamModifyAsync(
        ushort snapshotStreamID,
        bool? watermarkEnabled = default,
        bool? oSDEnabled = default,
        CancellationToken ct = default)
        => InvokeCommandAsync(0x0009, tlv =>
        {
            tlv.AddUInt16(0, snapshotStreamID);
            if (watermarkEnabled != null) tlv.AddBool(1, watermarkEnabled.Value);
            if (oSDEnabled != null) tlv.AddBool(2, oSDEnabled.Value);
        }, ct);

    /// <summary>Send SnapshotStreamDeallocate command (0x000A).</summary>
    public Task<InvokeResponse> SnapshotStreamDeallocateAsync(
        ushort snapshotStreamID,
        CancellationToken ct = default)
        => InvokeCommandAsync(0x000A, tlv => { tlv.AddUInt16(0, snapshotStreamID); }, ct);

    /// <summary>Send SetStreamPriorities command (0x000B).</summary>
    public Task<InvokeResponse> SetStreamPrioritiesAsync(
        StreamUsageEnum[] streamPriorities,
        CancellationToken ct = default)
        => InvokeCommandAsync(0x000B, tlv => { if (streamPriorities != null) { tlv.AddArray(0); foreach (var item in streamPriorities) { tlv.AddUInt8((byte)item); } tlv.EndContainer(); } }, ct);

    /// <summary>Send CaptureSnapshot command (0x000C).</summary>
    public Task<InvokeResponse> CaptureSnapshotAsync(
        ushort? snapshotStreamID,
        VideoResolutionStruct requestedResolution,
        CancellationToken ct = default)
        => InvokeCommandAsync(0x000C, tlv =>
        {
            if (snapshotStreamID != null) tlv.AddUInt16(0, snapshotStreamID.Value);
            WriteVideoResolutionStruct(tlv, 1, requestedResolution);
        }, ct);

